func (u *PromotionUpsertBulk) Update(set func(*PromotionUpsert)) *PromotionUpsertBulk {
	u.create.conflict = append(u.create.conflict, sql.ResolveWith(func(update *sql.UpdateSet) {
		set(&PromotionUpsert{UpdateSet: update})
	}))
	return u
}

